import math

def median_of_three(a, b, c):
    return sorted([a, b, c])[1]

def min_L_sum_for_x(x, eps=1e-9):
    # X can choose y in (0,x) or (x,1).
    # L sum = max + min of three pieces = 1 - median.
    # X minimizes L sum by maximizing median.

    sup_median = 0

    # y < x: pieces y, x-y, 1-x
    candidates_left = [0, x]  # boundaries (limits)
    for yc in [x/2, 1-x, 2*x-1]:
        if 0 < yc < x:
            candidates_left.append(yc)
    for y in candidates_left:
        if y == 0 or y == x:
            # limit: one piece -> 0
            # If y->0+: a=0, b=x, c=1-x => median = min(x, 1-x)
            val = min(x, 1-x)
        else:
            val = median_of_three(y, x-y, 1-x)
        if val > sup_median:
            sup_median = val

    # y > x: pieces x, y-x, 1-y
    candidates_right = [x, 1]
    for yc in [2*x, 1-x, (1+x)/2]:
        if x < yc < 1:
            candidates_right.append(yc)
    for y in candidates_right:
        if y == x or y == 1:
            # limit: one piece -> 0
            val = min(x, 1-x)
        else:
            val = median_of_three(x, y-x, 1-y)
        if val > sup_median:
            sup_median = val

    # X can achieve L sum arbitrarily close to 1 - sup_median
    return 1 - sup_median

# Evaluate
for x in [0.2, 0.25, 1/3, 0.4, 0.45, 0.5, 0.55, 0.6, 0.7, 0.75]:
    print(f"x={x:.4f}: min L sum = {min_L_sum_for_x(x):.6f}")

# Find optimal x
best_val = 0
best_x = None
for i in range(1, 1000):
    x = i/1000.0
    val = min_L_sum_for_x(x)
    if val > best_val:
        best_val = val
        best_x = x
print(f"\nOptimal x = {best_x}, guarantee = {best_val}")
