import itertools, math, random

def L_odd_abs(L_marks, X_marks):
    all_marks = sorted([0.0, 1.0] + L_marks + X_marks)
    pieces = [all_marks[i+1] - all_marks[i] for i in range(len(all_marks)-1)]
    pieces.sort(reverse=True)
    return sum(pieces[0::2])

def worst_L_random(L_marks, n, trials=500000):
    best_val = 1.0
    best_X = None
    for k in range(0, n+1):
        for _ in range(trials // (n+1)):
            X = []
            for __ in range(k):
                while True:
                    x = random.uniform(1e-9, 1-1e-9)
                    if all(abs(x - l) > 1e-9 for l in L_marks) and all(abs(x - y) > 1e-9 for y in X):
                        X.append(x)
                        break
            val = L_odd_abs(L_marks, X)
            if val < best_val:
                best_val = val
                best_X = (k, X)
    return best_val, best_X

def L_strategy(n):
    # marks at (2^k - 1)/(2^{n+1} - 1)
    denom = 2**(n+1) - 1
    return [(2**k - 1)/denom for k in range(1, n+1)]

for n in range(1, 5):
    L_marks = L_strategy(n)
    c = 2**n / (2**(n+1) - 1)
    print(f"n={n}: L marks = {[round(x,6) for x in L_marks]}, conjectured c = {c:.10f}")
    val, bx = worst_L_random(L_marks, n, trials=1000000)
    print(f"  Worst L sum (random search): {val:.10f}, X used {bx[0]} marks")
