import itertools
import random

def odd_sum(pieces):
    s = sorted(pieces, reverse=True)
    return sum(s[0::2])

# Discrete game: given initial pieces as integers, X can split an integer into two positive integers.
# We'll brute force all sequences of up to n splits for the binary initial set.

def all_splits(pieces, remaining_cuts):
    """Yield all possible multisets reachable."""
    if remaining_cuts == 0:
        yield tuple(sorted(pieces, reverse=True))
        return
    # Option: don't use all cuts
    yield tuple(sorted(pieces, reverse=True))
    for i, p in enumerate(pieces):
        if p >= 2:
            for a in range(1, p):
                b = p - a
                new_pieces = list(pieces)
                new_pieces.pop(i)
                new_pieces.append(a)
                new_pieces.append(b)
                for res in all_splits(new_pieces, remaining_cuts - 1):
                    yield res

def min_odd_for_n(n):
    initial = [2**i for i in range(n, -1, -1)]  # descending powers of 2
    best = float('inf')
    best_config = None
    for config in all_splits(initial, n):
        val = odd_sum(config)
        if val < best:
            best = val
            best_config = config
    return best, best_config

for n in range(1, 6):
    best, config = min_odd_for_n(n)
    print(f"n={n}: min odd sum = {best}, config = {config}")
    print(f"  Expected: {2**n}, ratio: {best/(2**(n+1)-1)}")
